<?phprequire_once(FRAME_WORK_PATH.'basic_classes/FieldSQL.php');require_once(FRAME_WORK_PATH.'Constants.php');class FieldSQLString extends FieldSQL{	/*	private function correctForDb($val){		return "'".$this->getDbLink()->escape_string($val)."'";	}	*/	public function __construct($dbLink,$dbName, $tableName,$id, $options=FALSE) {			$data_type = ($options && isset($options['dataType']))? $options['dataType'] : DT_STRING;			parent::__construct($dbLink,$dbName, $tableName,$id, $data_type,$options);	}			public function formatVal($val){		$formatted = null;		FieldSQLString::formatForDb($this->getDbLink(),$val,$formatted);		return $formatted;	}	public function getValueForDb(){				return $this->formatVal($this->getValue());	}	public function getOldValueForDb(){				return $this->formatVal($this->getOldValue());	}	public static function formatForDb($dbLink,$valIn,&$valOut){		$valOut = (!isset($valIn) || !strlen($valIn) || strtolower($valIn)=='null')? 'NULL':"'".$dbLink->escape_string($valIn)."'";		//	}		}?>